int sustained_high_traffic(double rate, int duration_in_seconds) {
    static double prev_rate = 0;
    static time_t last_time = 0;

    time_t curr_time = time(NULL);
    if (curr_time - last_time >= duration_in_seconds) {
        prev_rate = rate;
        last_time = curr_time;
    }

    return (rate > 10000 && prev_rate > 10000);
}

