void mmt_rule_satisfied_callback(const rule_t *rule, int verdict, uint64_t timestamp, uint64_t counter,
                                 const mmt_array_t * const trace) {
    if (verdict == DETECTED) {
        char alert_msg[256];
        snprintf(alert_msg, sizeof(alert_msg), "Abnormal traffic pattern detected on N3. Affected UE: %u",
                 gtpu.ue_id);
        mmt_log_info("MMT-Security", alert_msg);
    }
}
